import sys
from collections import defaultdict

def main():
    sys.setrecursionlimit(10000)
    N, M = map(int, sys.stdin.readline().split())
    relations = []
    for _ in range(M):
        A, B = map(int, sys.stdin.readline().split())
        relations.append((A, B))

    # Build adjacency list for graph
    graph = defaultdict(list)
    for A, B in relations:
        graph[A].append(B)

    # Function to perform DFS and find all reachable nodes
    def dfs(node, visited, reachable):
        visited.add(node)
        for neighbor in graph[node]:
            if neighbor not in visited:
                reachable.add(neighbor)
                dfs(neighbor, visited, reachable)

    # For each node, find all nodes it can reach (i.e., it is stronger than them)
    reachability = {}
    for node in range(1, N + 1):
        visited = set()
        reachable = set()
        dfs(node, visited, reachable)
        reachability[node] = reachable

    # Find all candidates that could be the strongest
    candidates = []
    for node in range(1, N + 1):
        # A node is a candidate if it can reach all other nodes
        if len(reachability[node]) == N - 1:
            candidates.append(node)

    if len(candidates) == 1:
        print(candidates[0])
    else:
        print(-1)

if __name__ == "__main__":
    main()
